void comInit() {

  fac[0] = fac[1] = 1;

  finv[0] = finv[1] = 1;

  inv[1] = 1;

  for (int i = 2; i < MAX; i++) {

    fac[i] = fac[i - 1] * i % Mod;

    inv[i] = Mod - inv[Mod % i] * (Mod / i) % Mod;

    finv[i] = finv[i - 1] * inv[i] % Mod;

  }

